import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { api } from '../../utils/api';
import { getTheme, cardStyle } from '../../utils/theme';
import { StatCard, PageLoader, StatusBadge, EmptyState } from '../../components/common/UI';

export default function PatientHome() {
  const { user, darkMode } = useAuth();
  const navigate = useNavigate();
  const t = getTheme(darkMode);
  const [appointments, setAppointments] = useState([]);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [emergency, setEmergency] = useState(false);
  const [ambProgress, setAmbProgress] = useState(0);

  useEffect(() => {
    Promise.all([api.appointments.my(), api.orders.my()])
      .then(([a, o]) => { setAppointments(a.data); setOrders(o.data); })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const upcoming = appointments.filter(a => new Date(a.date) > new Date() && a.status !== 'cancelled');
  const pending = orders.filter(o => ['pending','confirmed','processing'].includes(o.status));
  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good Morning' : hour < 18 ? 'Good Afternoon' : 'Good Evening';

  const requestAmbulance = () => {
    setEmergency(true);
    let p = 0;
    const iv = setInterval(() => {
      p += 8; setAmbProgress(Math.min(p, 100));
      if (p >= 100) { clearInterval(iv); alert('🚑 Ambulance has arrived! Please meet at the emergency entrance.'); setEmergency(false); setAmbProgress(0); }
    }, 400);
  };

  if (loading) return <PageLoader darkMode={darkMode} />;

  const QUICK = [
    { icon: '+ 📅', label: 'Book Appointment', to: '/patient/appointments', color: '#0891b2' },
    { icon: '👨‍⚕️', label: 'Find Doctors', to: '/patient/doctors', color: '#059669' },
    { icon: '💊', label: 'Order Medicine', to: '/patient/medicines', color: '#0d9488' },
    { icon: '🔬', label: 'Lab Reports', to: '/patient/lab-reports', color: '#8b5cf6' },
    { icon: '🎥', label: 'Video Call', to: '/patient/video-call', color: '#f59e0b' },
    { icon: '❤️', label: 'My Health', to: '/patient/health', color: '#ef4444' },
  ];

  return (
    <div style={{ background: t.bg, minHeight: '100vh', padding: 24 }}>
      <div style={{ maxWidth: 1280, margin: '0 auto' }}>

        {/* Hero Banner */}
        <div style={{ background: 'linear-gradient(135deg,#0f172a 0%,#0891b2 60%,#06b6d4 100%)', borderRadius: 22, padding: 'clamp(24px,4vw,36px) clamp(24px,4vw,40px)', color: 'white', marginBottom: 28, display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 20 }}>
          <div>
            <h1 style={{ fontSize: 'clamp(1.3rem,3vw,2rem)', fontWeight: 800, margin: 0 }}>{greeting}, {user?.name}! 👋</h1>
            <p style={{ opacity: 0.85, marginTop: 6, fontSize: 14 }}>Welcome to your personal health dashboard</p>
          </div>
          <div style={{ display: 'flex', gap: 14, flexWrap: 'wrap' }}>
            {[{ n: appointments.length, l: 'Appointments' }, { n: upcoming.length, l: 'Upcoming' }, { n: orders.length, l: 'Orders' }].map((s, i) => (
              <div key={i} style={{ background: 'rgba(255,255,255,0.15)', padding: '10px 18px', borderRadius: 12, textAlign: 'center', minWidth: 72 }}>
                <div style={{ fontSize: 22, fontWeight: 900 }}>{s.n}</div>
                <div style={{ fontSize: 11, opacity: 0.85 }}>{s.l}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Quick Actions */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(140px,1fr))', gap: 14, marginBottom: 28 }}>
          {QUICK.map((q, i) => (
            <Link key={i} to={q.to} style={{ textDecoration: 'none', background: t.card, borderRadius: 16, padding: '20px 14px', textAlign: 'center', border: `1px solid ${t.cardBorder}`, boxShadow: t.shadow, cursor: 'pointer', transition: 'all .18s', display: 'block' }}
              className="card-hover">
              <div style={{ fontSize: '1.9rem', marginBottom: 8 }}>{q.icon}</div>
              <div style={{ fontSize: 12, fontWeight: 700, color: t.text }}>{q.label}</div>
            </Link>
          ))}
        </div>

        {/* Main Grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(380px,1fr))', gap: 24 }}>

          {/* Upcoming Appointments */}
          <div style={{ ...cardStyle(t), padding: 28 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
              <h3 style={{ color: t.text, fontWeight: 700, fontSize: 16, margin: 0 }}>📅 Upcoming Appointments</h3>
              <Link to="/patient/appointments" style={{ color: '#0891b2', fontSize: 13, fontWeight: 600, textDecoration: 'none' }}>View All →</Link>
            </div>
            {upcoming.length === 0 ? (
              <EmptyState icon="📅" title="No upcoming appointments" desc="Book an appointment with a doctor" darkMode={darkMode}
                action={<Link to="/patient/appointments" style={{ background: 'linear-gradient(135deg,#0891b2,#06b6d4)', color: 'white', padding: '9px 20px', borderRadius: 10, textDecoration: 'none', fontSize: 13, fontWeight: 700 }}>Book Now</Link>} />
            ) : upcoming.slice(0, 3).map(apt => {
              const dName = apt.doctorId?.userId?.name || 'Doctor';
              return (
                <div key={apt._id} style={{ padding: '14px 0', borderBottom: `1px solid ${t.cardBorder}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div>
                    <div style={{ fontWeight: 700, color: t.text, fontSize: 14 }}>Dr. {dName}</div>
                    <div style={{ fontSize: 12, color: '#0891b2', marginTop: 2 }}>{apt.doctorId?.specialization}</div>
                    <div style={{ fontSize: 12, color: t.textSub, marginTop: 2 }}>📅 {new Date(apt.date).toLocaleString('en-IN', { dateStyle: 'medium', timeStyle: 'short' })}</div>
                  </div>
                  <StatusBadge status={apt.status} darkMode={darkMode} />
                </div>
              );
            })}
          </div>

          {/* Medicine Orders */}
          <div style={{ ...cardStyle(t), padding: 28 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
              <h3 style={{ color: t.text, fontWeight: 700, fontSize: 16, margin: 0 }}>💊 Recent Orders</h3>
              <Link to="/patient/medicines" style={{ color: '#0891b2', fontSize: 13, fontWeight: 600, textDecoration: 'none' }}>View All →</Link>
            </div>
            {orders.length === 0 ? (
              <EmptyState icon="🛒" title="No orders yet" desc="Order medicines with doorstep delivery" darkMode={darkMode}
                action={<Link to="/patient/medicines" style={{ background: 'linear-gradient(135deg,#0d9488,#059669)', color: 'white', padding: '9px 20px', borderRadius: 10, textDecoration: 'none', fontSize: 13, fontWeight: 700 }}>Order Now</Link>} />
            ) : orders.slice(0, 4).map(o => (
              <div key={o._id} style={{ padding: '12px 0', borderBottom: `1px solid ${t.cardBorder}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <div style={{ fontWeight: 600, color: t.text, fontSize: 13 }}>{o.items?.length} item{o.items?.length !== 1 ? 's' : ''} — ₹{o.totalAmount}</div>
                  <div style={{ fontSize: 11, color: t.textSub, marginTop: 2 }}>{new Date(o.createdAt).toLocaleDateString('en-IN')}</div>
                </div>
                <StatusBadge status={o.status} darkMode={darkMode} />
              </div>
            ))}
          </div>

          {/* Emergency */}
          <div style={{ ...cardStyle(t), padding: 28 }}>
            <h3 style={{ color: t.text, fontWeight: 700, fontSize: 16, marginBottom: 20 }}>🚑 Emergency Services</h3>
            {!emergency ? (
              <>
                <button onClick={requestAmbulance} style={{ width: '100%', padding: 16, background: 'linear-gradient(135deg,#ef4444,#dc2626)', color: 'white', border: 'none', borderRadius: 14, fontSize: 16, fontWeight: 800, cursor: 'pointer', marginBottom: 14 }}>
                  🚨 Request Ambulance
                </button>
                <div style={{ background: 'rgba(239,68,68,0.07)', borderRadius: 12, padding: 16, border: '1px solid rgba(239,68,68,0.15)' }}>
                  <p style={{ color: t.textSub, fontSize: 13, margin: 0 }}>📞 Emergency Helpline: <strong style={{ color: '#ef4444' }}>108</strong></p>
                  <p style={{ color: t.textSub, fontSize: 13, margin: '6px 0 0' }}>🏥 ICU Beds Available · ER Open 24/7</p>
                  <p style={{ color: t.textSub, fontSize: 13, margin: '6px 0 0' }}>🩺 Trauma Center: Active</p>
                </div>
              </>
            ) : (
              <div style={{ background: 'rgba(239,68,68,0.07)', borderRadius: 14, padding: 24, border: '1px solid rgba(239,68,68,0.2)' }}>
                <p style={{ fontWeight: 800, color: '#dc2626', marginBottom: 14, fontSize: 16 }}>🚑 Ambulance Dispatched!</p>
                <div style={{ background: t.cardBorder, borderRadius: 999, height: 10, marginBottom: 10, overflow: 'hidden' }}>
                  <div style={{ width: `${ambProgress}%`, height: '100%', background: 'linear-gradient(90deg,#ef4444,#dc2626)', transition: 'width .4s', borderRadius: 999 }} />
                </div>
                <p style={{ color: t.textSub, fontSize: 13 }}>Progress: {ambProgress}% · ETA: ~5 minutes</p>
                <p style={{ color: t.textSub, fontSize: 12, marginTop: 8 }}>📞 Stay on line: 108</p>
              </div>
            )}
          </div>

          {/* AI Symptom Checker - Enhanced with Medicine Suggestions */}
          <div style={{ ...cardStyle(t), padding: 28 }}>
            <h3 style={{ color: t.text, fontWeight: 700, fontSize: 16, marginBottom: 8 }}>🤖 AI Symptom Checker</h3>
            <p style={{ color: t.textSub, fontSize: 13, marginBottom: 20 }}>Get preliminary health analysis and medicine suggestions powered by AI</p>
            <AISymptomChecker darkMode={darkMode} t={t} navigate={navigate} />
          </div>
        </div>
      </div>
    </div>
  );
}

// Enhanced AI Symptom Checker with Medicine Suggestions
function AISymptomChecker({ darkMode, t, navigate }) {
  const [input, setInput] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  // Medicine Database
  const getMedicineSuggestions = (symptoms) => {
    const s = symptoms.toLowerCase();

    if (s.includes('fever')) {
      return {
        medicines: [
          { name: 'Paracetamol 500mg', dosage: '1 tablet every 4-6 hours', maxDose: 'Max 4 tablets in 24 hours', price: '₹25', type: 'OTC' },
          { name: 'Ibuprofen 400mg', dosage: '1 tablet every 6-8 hours', maxDose: 'Max 3 tablets in 24 hours', price: '₹35', type: 'OTC' }
        ],
        homeRemedies: ['💧 Drink plenty of fluids', '🛏️ Get adequate rest', '🧊 Use cold compress', '🍵 Drink herbal tea'],
        warningSigns: ['Fever > 104°F (40°C)', 'Fever lasting > 3 days', 'Severe headache or stiff neck']
      };
    }

    if (s.includes('headache')) {
      return {
        medicines: [
          { name: 'Aspirin 75mg', dosage: '1 tablet every 4-6 hours', maxDose: 'Max 4 tablets in 24 hours', price: '₹20', type: 'OTC' },
          { name: 'Paracetamol 500mg', dosage: '1 tablet every 4-6 hours', maxDose: 'Max 4 tablets in 24 hours', price: '₹25', type: 'OTC' }
        ],
        homeRemedies: ['💧 Drink water', '😴 Rest in dark room', '❄️ Cold compress on forehead', '☕ Small amount of caffeine'],
        warningSigns: ['Sudden severe headache', 'Headache with fever', 'Headache after head injury']
      };
    }

    if (s.includes('cold') || s.includes('cough')) {
      return {
        medicines: [
          { name: 'Cetirizine 10mg', dosage: '1 tablet daily', maxDose: 'Once daily', price: '₹30', type: 'OTC' },
          { name: 'Cough Syrup', dosage: '10ml 3 times daily', maxDose: 'As directed', price: '₹85', type: 'OTC' }
        ],
        homeRemedies: ['🍯 Honey with warm water', '🫚 Ginger tea', '💨 Steam inhalation', '🥣 Warm soup'],
        warningSigns: ['Cough with blood', 'Difficulty breathing', 'High fever > 3 days']
      };
    }

    if (s.includes('stomach') || s.includes('acidity')) {
      return {
        medicines: [
          { name: 'Digene Gel', dosage: '2 tablets after meals', maxDose: 'As needed', price: '₹30', type: 'OTC' },
          { name: 'Omeprazole 20mg', dosage: '1 capsule daily', maxDose: 'Once daily', price: '₹55', type: 'Prescription' }
        ],
        homeRemedies: ['🍵 Peppermint tea', '💧 Warm water', '🍚 Light bland foods', '🌿 Ajwain with warm water'],
        warningSigns: ['Severe pain', 'Blood in vomit/stool', 'Fever with pain']
      };
    }

    if (s.includes('body pain') || s.includes('muscle pain')) {
      return {
        medicines: [
          { name: 'Paracetamol 500mg', dosage: '1 tablet every 4-6 hours', maxDose: 'Max 4 tablets/24h', price: '₹25', type: 'OTC' },
          { name: 'Diclofenac Gel', dosage: 'Apply 3-4 times daily', maxDose: 'External use', price: '₹60', type: 'OTC' }
        ],
        homeRemedies: ['🛀 Warm bath', '💆 Gentle massage', '🛏️ Rest', '🧊 Cold compress'],
        warningSigns: ['Severe swelling', 'Pain > 7 days', 'Pain with fever']
      };
    }

    return null;
  };

  const analyze = () => {
    if (!input.trim()) return;
    setLoading(true);

    setTimeout(() => {
      const s = input.toLowerCase();
      let response = '';
      let urgency = 'low';
      let suggestions = [];
      let medicines = null;
      let disclaimer = '';

      // Emergency conditions
      if (s.includes('chest pain') || s.includes('heart attack') || s.includes('difficulty breathing')) {
        urgency = 'emergency';
        response = '⚠️ URGENT: These symptoms require immediate medical attention! Please seek emergency care right away.';
        suggestions = ['Call 108 immediately', 'Do not drive yourself', 'Stay calm and rest', 'Loosen tight clothing'];
        medicines = null;
        disclaimer = 'This is an emergency situation. Please seek immediate medical attention.';
      }
      // Fever
      else if (s.includes('fever')) {
        urgency = 'medium';
        response = '🤒 Based on your symptoms of fever, here are some recommendations to help manage your condition.';
        medicines = getMedicineSuggestions('fever');
        suggestions = medicines?.homeRemedies || [];
        disclaimer = '⚠️ MEDICAL DISCLAIMER: This is an AI-generated suggestion. Please consult a doctor before taking any medication. Self-medication can be harmful.';
      }
      // Headache
      else if (s.includes('headache') || s.includes('migraine')) {
        urgency = 'low';
        response = '🧠 Based on your headache symptoms, here are some suggestions for relief.';
        medicines = getMedicineSuggestions('headache');
        suggestions = medicines?.homeRemedies || [];
        disclaimer = '⚠️ MEDICAL DISCLAIMER: This is an AI-generated suggestion. Consult a doctor if headache persists or worsens.';
      }
      // Cold/Cough
      else if (s.includes('cold') || s.includes('cough') || s.includes('flu')) {
        urgency = 'medium';
        response = '🤧 Based on your cold/cough symptoms, here are some recommendations for relief.';
        medicines = getMedicineSuggestions('cold');
        suggestions = medicines?.homeRemedies || [];
        disclaimer = '⚠️ MEDICAL DISCLAIMER: These are over-the-counter suggestions. Consult a doctor if symptoms persist beyond 5-7 days.';
      }
      // Stomach issues
      else if (s.includes('stomach') || s.includes('acidity') || s.includes('indigestion')) {
        urgency = 'medium';
        response = '🍽️ Based on your stomach discomfort, here are some suggestions for relief.';
        medicines = getMedicineSuggestions('stomach');
        suggestions = medicines?.homeRemedies || [];
        disclaimer = '⚠️ MEDICAL DISCLAIMER: Consult a doctor if pain is severe or persists.';
      }
      // Body pain
      else if (s.includes('body pain') || s.includes('muscle pain') || s.includes('joint pain')) {
        urgency = 'low';
        response = '💪 Based on your body pain symptoms, here are some suggestions for relief.';
        medicines = getMedicineSuggestions('body pain');
        suggestions = medicines?.homeRemedies || [];
        disclaimer = '⚠️ MEDICAL DISCLAIMER: If pain is severe or persists, please consult a doctor.';
      }
      else {
        urgency = 'low';
        response = '📝 Symptoms noted. Please consult a doctor for accurate diagnosis and treatment.';
        suggestions = ['Book an appointment with a doctor', 'Track your symptoms daily', 'Stay hydrated and rest well'];
        medicines = null;
        disclaimer = '⚠️ DISCLAIMER: This is not a medical diagnosis. Please consult a healthcare professional.';
      }

      setResult({ response, urgency, suggestions, medicines, disclaimer });
      setLoading(false);
    }, 1000);
  };

  const urgencyColor = { emergency: '#dc2626', high: '#ea580c', medium: '#d97706', low: '#10b981' };
  const uc = result ? urgencyColor[result.urgency] : '#0891b2';

  const handleOrderMedicine = (medicine) => {
    alert(`💊 ${medicine.name} added to cart!\n\nDosage: ${medicine.dosage}\nMax Dose: ${medicine.maxDose}\nPrice: ${medicine.price}\n\nPlease consult a doctor before taking any medication.`);
  };

  return (
    <div>
      <textarea 
        value={input} 
        onChange={e => setInput(e.target.value)} 
        placeholder="Describe your symptoms in detail... (e.g., fever with headache since yesterday, chest pain, cold and cough, stomach pain)" 
        style={{ 
          width: '100%', 
          padding: '12px 14px', 
          borderRadius: 10, 
          border: `1px solid ${t.cardBorder}`, 
          background: t.inputBg, 
          color: t.text, 
          fontSize: 13, 
          outline: 'none', 
          minHeight: 100, 
          resize: 'vertical', 
          boxSizing: 'border-box', 
          marginBottom: 10 
        }} 
      />

      <button 
        onClick={analyze} 
        disabled={loading} 
        style={{ 
          width: '100%', 
          padding: '10px', 
          background: 'linear-gradient(135deg,#8b5cf6,#7c3aed)', 
          color: 'white', 
          border: 'none', 
          borderRadius: 10, 
          fontSize: 14, 
          fontWeight: 700, 
          cursor: 'pointer', 
          marginBottom: result ? 14 : 0 
        }}
      >
        {loading ? '⏳ Analyzing...' : '🤖 Analyze Symptoms'}
      </button>

      {result && (
        <div style={{ 
          background: uc + '12', 
          border: `1px solid ${uc}40`, 
          borderLeft: `4px solid ${uc}`, 
          borderRadius: 12, 
          padding: 16,
          marginTop: 8
        }}>
          {/* Urgency Badge */}
          <div style={{ 
            display: 'inline-block', 
            background: uc, 
            color: 'white', 
            padding: '4px 12px', 
            borderRadius: 20, 
            fontSize: 11, 
            fontWeight: 700,
            marginBottom: 12
          }}>
            {result.urgency.toUpperCase()} URGENCY
          </div>

          {/* AI Response */}
          <p style={{ color: uc, fontWeight: 700, marginBottom: 10, fontSize: 14 }}>AI Analysis:</p>
          <p style={{ color: t.text, fontSize: 13, marginBottom: 12, lineHeight: 1.5 }}>{result.response}</p>

          {/* Medicine Suggestions */}
          {result.medicines && result.medicines.medicines && result.medicines.medicines.length > 0 && (
            <div style={{ marginBottom: 14 }}>
              <p style={{ fontWeight: 700, color: t.text, fontSize: 13, marginBottom: 8 }}>💊 Suggested Medicines:</p>
              {result.medicines.medicines.map((med, idx) => (
                <div key={idx} style={{ 
                  background: darkMode ? '#0f172a' : '#f8fafc', 
                  borderRadius: 10, 
                  padding: 10, 
                  marginBottom: 8,
                  border: `1px solid ${uc}20`
                }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 8 }}>
                    <div>
                      <div style={{ fontWeight: 700, color: t.text, fontSize: 14 }}>{med.name}</div>
                      <div style={{ fontSize: 11, color: t.textSub }}>Dosage: {med.dosage}</div>
                      <div style={{ fontSize: 11, color: t.textSub }}>Max: {med.maxDose}</div>
                    </div>
                    <div>
                      <div style={{ fontSize: 16, fontWeight: 700, color: '#0891b2' }}>{med.price}</div>
                      <div style={{ fontSize: 10, color: med.type === 'Prescription' ? '#f59e0b' : '#10b981' }}>{med.type}</div>
                    </div>
                  </div>
                  <button 
                    onClick={() => handleOrderMedicine(med)} 
                    style={{ 
                      width: '100%', 
                      marginTop: 8, 
                      padding: '6px', 
                      background: 'linear-gradient(135deg,#0891b2,#06b6d4)', 
                      color: 'white', 
                      border: 'none', 
                      borderRadius: 8, 
                      fontSize: 12, 
                      fontWeight: 600, 
                      cursor: 'pointer' 
                    }}
                  >
                    🛒 Order Now
                  </button>
                </div>
              ))}
            </div>
          )}

          {/* Home Remedies */}
          {result.suggestions && result.suggestions.length > 0 && (
            <div style={{ marginBottom: 12 }}>
              <p style={{ fontWeight: 700, color: t.text, fontSize: 13, marginBottom: 6 }}>🏠 Home Remedies & Tips:</p>
              <ul style={{ paddingLeft: 18, color: t.textSub, fontSize: 12 }}>
                {result.suggestions.slice(0, 4).map((s, i) => (
                  <li key={i} style={{ marginBottom: 4 }}>{s}</li>
                ))}
              </ul>
            </div>
          )}

          {/* Warning Signs */}
          {result.medicines?.warningSigns && (
            <div style={{ marginBottom: 12, background: '#fee2e2', borderRadius: 8, padding: 10 }}>
              <p style={{ fontWeight: 700, color: '#dc2626', fontSize: 12, marginBottom: 6 }}>⚠️ Warning Signs - Seek Medical Help If:</p>
              <ul style={{ paddingLeft: 18, color: '#991b1b', fontSize: 11 }}>
                {result.medicines.warningSigns.map((w, i) => (
                  <li key={i} style={{ marginBottom: 3 }}>{w}</li>
                ))}
              </ul>
            </div>
          )}

          {/* Disclaimer */}
          <div style={{ 
            background: darkMode ? '#0f172a' : '#fef3c7', 
            borderRadius: 8, 
            padding: 10, 
            marginTop: 8,
            borderLeft: `3px solid #f59e0b`
          }}>
            <p style={{ fontSize: 11, color: '#92400e', margin: 0, lineHeight: 1.4 }}>
              {result.disclaimer || '⚠️ DISCLAIMER: This is an AI-generated analysis and not a substitute for professional medical advice. Always consult a qualified healthcare provider.'}
            </p>
          </div>

          {/* Action Buttons */}
          <div style={{ display: 'flex', gap: 10, marginTop: 14 }}>
            {result.urgency !== 'low' && (
              <button 
                onClick={() => navigate('/patient/appointments')} 
                style={{ 
                  flex: 1, 
                  padding: '8px 16px', 
                  background: 'linear-gradient(135deg,#0891b2,#06b6d4)', 
                  color: 'white', 
                  border: 'none', 
                  borderRadius: 8, 
                  fontSize: 13, 
                  fontWeight: 700, 
                  cursor: 'pointer' 
                }}
              >
                📅 Book Appointment
              </button>
            )}
            {result.urgency === 'emergency' && (
              <button 
                onClick={() => window.location.href = 'tel:108'} 
                style={{ 
                  flex: 1, 
                  padding: '8px 16px', 
                  background: 'linear-gradient(135deg,#ef4444,#dc2626)', 
                  color: 'white', 
                  border: 'none', 
                  borderRadius: 8, 
                  fontSize: 13, 
                  fontWeight: 700, 
                  cursor: 'pointer' 
                }}
              >
                📞 Call 108 Emergency
              </button>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
